import{_ as a,c as t,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Integración con Bear: Guardar Planes Automáticamente | Plannotator","description":"Aprende a configurar la integración de Plannotator con Bear. Guarda automáticamente los planes aprobados mediante x-callback-url, genera etiquetas inteligentes y archiva tu conocimiento.","frontmatter":{"title":"Integración con Bear: Guardar Planes Automáticamente | Plannotator","sidebarTitle":"Guardar Planes en Bear","subtitle":"Integración con Bear: Guardar Planes Aprobados Automáticamente | Plannotator","description":"Aprende a configurar la integración de Plannotator con Bear. Guarda automáticamente los planes aprobados mediante x-callback-url, genera etiquetas inteligentes y archiva tu conocimiento.","tags":["Integración","Bear","Aplicación de notas","Gestión del conocimiento"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"es/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"es/backnotprop/plannotator/advanced/bear-integration/index.md"}'),n={name:"es/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(l,e,s,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="integracion-con-bear-guardar-planes-aprobados-automaticamente" tabindex="-1">Integración con Bear: Guardar Planes Aprobados Automáticamente <a class="header-anchor" href="#integracion-con-bear-guardar-planes-aprobados-automaticamente" aria-label="Permalink to &quot;Integración con Bear: Guardar Planes Aprobados Automáticamente&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><p>Al habilitar la integración con Bear, cada vez que apruebes un plan, Plannotator lo guardará automáticamente en tus notas de Bear, incluyendo:</p><ul><li>Un título generado automáticamente (extraído del plan)</li><li>Etiquetas inteligentes (nombre del proyecto, palabras clave, lenguajes de programación)</li><li>El contenido completo del plan</li></ul><p>De esta manera, podrás gestionar todos tus planes aprobados en un solo lugar, facilitando la consulta posterior y la acumulación de conocimiento.</p><h2 id="el-problema-que-enfrentas" tabindex="-1">El problema que enfrentas <a class="header-anchor" href="#el-problema-que-enfrentas" aria-label="Permalink to &quot;El problema que enfrentas&quot;">​</a></h2><p>Probablemente te hayas encontrado con estas situaciones:</p><ul><li>El plan generado por la IA es excelente, pero quieres guardarlo para consultarlo más tarde</li><li>Copiar y pegar planes manualmente en Bear es tedioso</li><li>Los planes de diferentes proyectos están mezclados, sin gestión de etiquetas</li></ul><p>Con la integración de Bear, todos estos problemas se resuelven automáticamente.</p><h2 id="cuando-usar-esta-funcion" tabindex="-1">Cuándo usar esta función <a class="header-anchor" href="#cuando-usar-esta-funcion" aria-label="Permalink to &quot;Cuándo usar esta función&quot;">​</a></h2><ul><li>Usas Bear como tu aplicación principal de notas</li><li>Necesitas archivar planes aprobados como base de conocimiento</li><li>Quieres buscar rápidamente planes históricos mediante etiquetas</li></ul><div class="info custom-block"><p class="custom-block-title">Acerca de Bear</p><p>Bear es una aplicación de notas Markdown para macOS que soporta etiquetas, cifrado, sincronización y más. Si aún no la tienes instalada, visita <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> para más información.</p></div><h2 id="🎒-antes-de-empezar" tabindex="-1">🎒 Antes de empezar <a class="header-anchor" href="#🎒-antes-de-empezar" aria-label="Permalink to &quot;🎒 Antes de empezar&quot;">​</a></h2><ul><li>Tener Plannotator instalado (consulta el <a href="./../../start/installation-claude-code/">tutorial de instalación</a>)</li><li>Tener Bear instalado y funcionando correctamente</li><li>Conocer el flujo básico de revisión de planes (consulta <a href="./../../platforms/plan-review-basics/">Fundamentos de revisión de planes</a>)</li></ul><h2 id="concepto-clave" tabindex="-1">Concepto clave <a class="header-anchor" href="#concepto-clave" aria-label="Permalink to &quot;Concepto clave&quot;">​</a></h2><p>El núcleo de la integración con Bear es el protocolo <strong>x-callback-url</strong>:</p><ol><li>Habilita la integración con Bear en la interfaz de Plannotator (se almacena en localStorage del navegador)</li><li>Al aprobar un plan, Plannotator envía una URL <code>bear://x-callback-url/create</code></li><li>El sistema usa el comando <code>open</code> para abrir Bear automáticamente y crear una nota</li><li>El contenido del plan, título y etiquetas se rellenan automáticamente</li></ol><p><strong>Características clave</strong>:</p><ul><li>No requiere configurar la ruta del vault (a diferencia de Obsidian)</li><li>Generación inteligente de etiquetas (máximo 7)</li><li>Guardado automático al aprobar el plan</li></ul><div class="tip custom-block"><p class="custom-block-title">Diferencia con Obsidian</p><p>La integración con Bear es más sencilla, no necesitas configurar la ruta del vault, solo un interruptor. Sin embargo, Obsidian permite especificar la carpeta de destino y más personalización.</p></div><h2 id="paso-a-paso" tabindex="-1">Paso a paso <a class="header-anchor" href="#paso-a-paso" aria-label="Permalink to &quot;Paso a paso&quot;">​</a></h2><h3 id="paso-1-abrir-la-configuracion-de-plannotator" tabindex="-1">Paso 1: Abrir la configuración de Plannotator <a class="header-anchor" href="#paso-1-abrir-la-configuracion-de-plannotator" aria-label="Permalink to &quot;Paso 1: Abrir la configuración de Plannotator&quot;">​</a></h3><p>Cuando el agente de IA genere un plan y abra la interfaz de Plannotator, haz clic en el botón ⚙️ <strong>Settings</strong> en la esquina superior derecha.</p><p><strong>Deberías ver</strong>: El panel de configuración aparece con varias opciones</p><h3 id="paso-2-habilitar-la-integracion-con-bear" tabindex="-1">Paso 2: Habilitar la integración con Bear <a class="header-anchor" href="#paso-2-habilitar-la-integracion-con-bear" aria-label="Permalink to &quot;Paso 2: Habilitar la integración con Bear&quot;">​</a></h3><p>En el panel de configuración, busca la sección <strong>Bear Notes</strong> y activa el interruptor.</p><p><strong>Por qué</strong> El interruptor cambiará de gris (deshabilitado) a azul (habilitado), y se guardará en el localStorage del navegador.</p><p><strong>Deberías ver</strong>:</p><ul><li>El interruptor de Bear Notes en azul</li><li>El texto descriptivo: &quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="paso-3-aprobar-el-plan" tabindex="-1">Paso 3: Aprobar el plan <a class="header-anchor" href="#paso-3-aprobar-el-plan" aria-label="Permalink to &quot;Paso 3: Aprobar el plan&quot;">​</a></h3><p>Después de completar la revisión del plan, haz clic en el botón <strong>Approve</strong> en la parte inferior.</p><p><strong>Por qué</strong> Plannotator leerá la configuración de Bear y, si está habilitada, llamará al x-callback-url de Bear al mismo tiempo que aprueba.</p><p><strong>Deberías ver</strong>:</p><ul><li>La aplicación Bear se abre automáticamente</li><li>Aparece la ventana de nueva nota</li><li>El título y contenido ya están rellenados</li><li>Las etiquetas se han generado automáticamente (comenzando con <code>#</code>)</li></ul><h3 id="paso-4-verificar-la-nota-guardada" tabindex="-1">Paso 4: Verificar la nota guardada <a class="header-anchor" href="#paso-4-verificar-la-nota-guardada" aria-label="Permalink to &quot;Paso 4: Verificar la nota guardada&quot;">​</a></h3><p>En Bear, revisa la nota recién creada y confirma:</p><ul><li>¿El título es correcto? (proviene del H1 del plan)</li><li>¿El contenido está completo? (incluye el texto completo del plan)</li><li>¿Las etiquetas son apropiadas? (nombre del proyecto, palabras clave, lenguaje de programación)</li></ul><p><strong>Deberías ver</strong>: Una estructura de nota similar a esta:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Contenido completo del plan...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="lista-de-verificacion-✅" tabindex="-1">Lista de verificación ✅ <a class="header-anchor" href="#lista-de-verificacion-✅" aria-label="Permalink to &quot;Lista de verificación ✅&quot;">​</a></h2><ul><li>[ ] El interruptor de Bear Notes está habilitado en Settings</li><li>[ ] Bear se abre automáticamente después de aprobar el plan</li><li>[ ] El título de la nota coincide con el H1 del plan</li><li>[ ] La nota contiene el contenido completo del plan</li><li>[ ] Las etiquetas incluyen <code>#plannotator</code> y el nombre del proyecto</li></ul><h2 id="solucion-de-problemas" tabindex="-1">Solución de problemas <a class="header-anchor" href="#solucion-de-problemas" aria-label="Permalink to &quot;Solución de problemas&quot;">​</a></h2><h3 id="bear-no-se-abre-automaticamente" tabindex="-1">Bear no se abre automáticamente <a class="header-anchor" href="#bear-no-se-abre-automaticamente" aria-label="Permalink to &quot;Bear no se abre automáticamente&quot;">​</a></h3><p><strong>Causa</strong>: El comando <code>open</code> del sistema falló, posiblemente porque:</p><ul><li>Bear no está instalado o no se descargó desde la App Store</li><li>El esquema de URL de Bear fue secuestrado por otra aplicación</li></ul><p><strong>Solución</strong>:</p><ol><li>Confirma que Bear está instalado correctamente</li><li>Prueba manualmente en la terminal: <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="las-etiquetas-no-son-las-esperadas" tabindex="-1">Las etiquetas no son las esperadas <a class="header-anchor" href="#las-etiquetas-no-son-las-esperadas" aria-label="Permalink to &quot;Las etiquetas no son las esperadas&quot;">​</a></h3><p><strong>Causa</strong>: Las etiquetas se generan automáticamente según estas reglas:</p><ul><li>Obligatoria: <code>#plannotator</code></li><li>Obligatoria: nombre del proyecto (extraído del nombre del repositorio git o del directorio)</li><li>Opcional: hasta 3 palabras clave extraídas del título H1 (excluyendo palabras vacías)</li><li>Opcional: etiquetas de lenguaje de programación extraídas de los bloques de código (excluyendo json/yaml/markdown)</li><li>Máximo 7 etiquetas</li></ul><p><strong>Solución</strong>:</p><ul><li>Si las etiquetas no son las esperadas, puedes editarlas manualmente en Bear</li><li>Si el nombre del proyecto es incorrecto, verifica la configuración del repositorio git o el nombre del directorio</li></ul><h3 id="plan-aprobado-pero-no-guardado" tabindex="-1">Plan aprobado pero no guardado <a class="header-anchor" href="#plan-aprobado-pero-no-guardado" aria-label="Permalink to &quot;Plan aprobado pero no guardado&quot;">​</a></h3><p><strong>Causa</strong>:</p><ul><li>El interruptor de Bear no está habilitado (verifica Settings)</li><li>Error de red o tiempo de espera de respuesta de Bear</li><li>El contenido del plan está vacío</li></ul><p><strong>Solución</strong>:</p><ol><li>Confirma que el interruptor en Settings está azul (estado habilitado)</li><li>Revisa si hay mensajes de error en la terminal (<code>[Bear] Save failed:</code>)</li><li>Vuelve a aprobar el plan</li></ol><h2 id="mecanismo-de-generacion-de-etiquetas-en-detalle" tabindex="-1">Mecanismo de generación de etiquetas en detalle <a class="header-anchor" href="#mecanismo-de-generacion-de-etiquetas-en-detalle" aria-label="Permalink to &quot;Mecanismo de generación de etiquetas en detalle&quot;">​</a></h2><p>Plannotator genera etiquetas inteligentes para que puedas buscar planes rápidamente en Bear. Estas son las reglas de generación:</p><table tabindex="0"><thead><tr><th>Fuente de etiqueta</th><th>Ejemplo</th><th>Prioridad</th></tr></thead><tbody><tr><td>Etiqueta fija</td><td><code>#plannotator</code></td><td>Obligatoria</td></tr><tr><td>Nombre del proyecto</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>Obligatoria</td></tr><tr><td>Palabras clave del H1</td><td><code>#authentication</code>, <code>#api</code></td><td>Opcional (máx. 3)</td></tr><tr><td>Lenguaje de programación</td><td><code>#typescript</code>, <code>#python</code></td><td>Opcional</td></tr></tbody></table><p><strong>Lista de palabras vacías</strong> (no se usarán como etiquetas):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>Lenguajes de programación excluidos</strong> (no se usarán como etiquetas):</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>Ejemplo: Proceso de generación de etiquetas</summary><p>Supongamos que el título del plan es &quot;Implementation Plan: User Authentication System in TypeScript&quot;, y los bloques de código contienen Python y JSON:</p><ol><li><strong>Etiqueta fija</strong>: <code>#plannotator</code></li><li><strong>Nombre del proyecto</strong>: <code>#myproject</code> (asumiendo el nombre del repositorio git)</li><li><strong>Palabras clave del H1</strong>: <ul><li><code>implementation</code> → excluida (palabra vacía)</li><li><code>plan</code> → excluida (palabra vacía)</li><li><code>user</code> → conservada → <code>#user</code></li><li><code>authentication</code> → conservada → <code>#authentication</code></li><li><code>system</code> → conservada → <code>#system</code></li><li><code>typescript</code> → conservada → <code>#typescript</code></li></ul></li><li><strong>Lenguajes de programación</strong>: <ul><li><code>python</code> → conservado → <code>#python</code></li><li><code>json</code> → excluido (lista de exclusión)</li></ul></li></ol><p>Etiquetas finales: <code>#plannotator #myproject #user #authentication #system #typescript #python</code> (7, alcanzando el límite)</p></details><h2 id="comparacion-con-la-integracion-de-obsidian" tabindex="-1">Comparación con la integración de Obsidian <a class="header-anchor" href="#comparacion-con-la-integracion-de-obsidian" aria-label="Permalink to &quot;Comparación con la integración de Obsidian&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Integración con Bear</th><th>Integración con Obsidian</th></tr></thead><tbody><tr><td>Complejidad de configuración</td><td>Simple (solo un interruptor)</td><td>Media (requiere seleccionar vault y carpeta)</td></tr><tr><td>Almacenamiento</td><td>Dentro de la app Bear</td><td>Ruta del vault especificada</td></tr><tr><td>Nombre del archivo</td><td>Gestionado automáticamente por Bear</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>No (Bear no lo soporta)</td><td>Sí (created, source, tags)</td></tr><tr><td>Multiplataforma</td><td>Solo macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ Utilizado</td><td>❌ Escritura directa de archivos</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Cómo elegir</p><ul><li>Si solo usas macOS y te gusta Bear: la integración con Bear es más sencilla</li><li>Si necesitas multiplataforma o rutas de almacenamiento personalizadas: la integración con Obsidian es más flexible</li><li>Si quieres usar ambos: puedes habilitar ambos (al aprobar el plan se guardará en ambos lugares)</li></ul></div><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><ul><li>La integración con Bear funciona mediante el protocolo x-callback-url, con configuración sencilla</li><li>Solo necesitas activar el interruptor en Settings, sin especificar rutas</li><li>Se guarda automáticamente en Bear al aprobar el plan</li><li>Las etiquetas se generan inteligentemente, incluyendo nombre del proyecto, palabras clave y lenguaje de programación (máximo 7)</li><li>Comparada con la integración de Obsidian, Bear es más simple pero con menos funciones</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos sobre el <strong><a href="./../remote-mode/">Modo Remoto/Devcontainer</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo usar Plannotator en entornos remotos (SSH, devcontainer, WSL)</li><li>Configurar puertos fijos y reenvío de puertos</li><li>Abrir el navegador en entornos remotos para ver la página de revisión</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver la ubicación del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Interfaz de configuración de Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Guardar en Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>Extracción de etiquetas</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Extracción de título</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Interfaz de configuración de Bear (UI)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Leer configuración de Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Guardar configuración de Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>Componente de configuración UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>Llamar a Bear al aprobar</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>Procesamiento del servidor para Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>Funciones clave</strong>:</p><ul><li><code>saveToBear(config: BearConfig)</code>: Guarda el plan en Bear mediante x-callback-url</li><li><code>extractTags(markdown: string)</code>: Extrae etiquetas inteligentemente del contenido del plan (máximo 7)</li><li><code>extractTitle(markdown: string)</code>: Extrae el título de la nota del encabezado H1 del plan</li><li><code>getBearSettings()</code>: Lee la configuración de integración con Bear desde localStorage</li><li><code>saveBearSettings(settings)</code>: Guarda la configuración de integración con Bear en localStorage</li></ul><p><strong>Constantes clave</strong>:</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>: Nombre de la clave de configuración de Bear en localStorage</li></ul><p><strong>Formato de URL de Bear</strong>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const b=a(n,[["render",i]]);export{m as __pageData,b as default};
